mapper.select:
SELECT DISTINCT h.*
FROM hotel h
JOIN(
SELECT * FROM room_type


            AND max_occupancy >= #{numberOfGuests}


) rt ON rt.hotel_id = h.id
JOIN (
SELECT room_type_id
FROM room_type_inventory



            AND date BETWEEN #{startDate} AND #{endDate}

                AND (total_inventory - total_reserved) >= #{numberOfRooms}



            AND date = #{today}

                AND (total_inventory - total_reserved) >= #{numberOfRooms}




GROUP BY room_type_id



            HAVING COUNT(date) >= #{totalDays}


            HAVING COUNT(date) >= 1


) i ON i.room_type_id = rt.id



        AND h.l_dong_regn_cd = #{lDongRegnCd}


        AND h.l_dong_signgu_cd = #{lDongSignguCd}



        AND h.lcls_systm2 = #{lclsSystm2}



        AND h.id > #{cursorId}


ORDER BY h.id ASC
LIMIT #{size}
